import{_ as o,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"高管薪酬","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/高管薪酬.md","filePath":"05_quotes/by-theme/高管薪酬.md"}'),r={name:"05_quotes/by-theme/高管薪酬.md"};function l(q,t,c,_,p,s){return e(),a("div",null,[...t[0]||(t[0]=[u('<h1 id="高管薪酬" tabindex="-1">高管薪酬 <a class="header-anchor" href="#高管薪酬" aria-label="Permalink to &quot;高管薪酬&quot;">​</a></h1><blockquote><p>&quot;激励必须与结果挂钩，简单可衡量。否则激励就会变成反向激励。&quot;——巴菲特</p></blockquote><p>高管薪酬是公司治理的核心问题，也是巴菲特批评最多的领域之一。</p><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;期权激励本身没有问题，但必须是合理的。问题在于，当期权行权价远低于市场价格时，激励就变成了奖励——与业绩无关的奖励。&quot;</p></blockquote><blockquote><p>&quot;GEICO的薪酬方案体现了我们的激励哲学：目标应该与经济现实挂钩，简单可衡量，与参与者日常活动直接相关。&quot;</p></blockquote><blockquote><p>&quot;我们避开&#39;彩票&#39;式的安排，比如伯克希尔股票的期权，其最终价值完全不在管理者控制之下。&quot;</p></blockquote><blockquote><p>&quot;一个产生异想天开薪酬的制度不仅对所有者是浪费的，而且实际上可能阻碍我们重视的管理者的专注行为。&quot;</p></blockquote><blockquote><p>&quot;CEO薪酬应该反映业绩，而不是反映市场惯例或者猎头公司给的参考值。如果一个CEO做得很差，给他市场价的薪酬是对股东的背叛。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1992年 · 1996年 · 2005年 · 2008年 · 2010年 · 2020年</p>',13)])])}const h=o(r,[["render",l]]);export{i as __pageData,h as default};
